    dist[0][0] = 0;
    heap.push(Reverse((0, 0, 0)));

    while let Some(Reverse((d, u, used))) = heap.pop() {
        if u == n - 1 {
            return d;
        }
        if d > dist[u][used] {
            continue;
        }
        // Normal edges
        for &(v, w) in &adj[u] {
