    cost: i64,
    node: usize,
    used_switch: bool,
}

impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        other.cost.cmp(&self.cost)
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    let n = n as usize;
    let mut adj = vec![vec![]; n];
    let mut rev_adj = vec![vec![]; n];

    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let w = edge[2];
        adj[u].push((v, w));
        rev_adj[v].push((u, w));
    }

    let mut dist = vec![vec![i64::MAX; 2]; n];
    let mut heap = BinaryHeap::new();

    dist[0][0] = 0;
    heap.push(State { cost: 0, node: 0, used_switch: false });

    while let Some(State { cost, node, used_switch }) = heap.pop() {
        if node == n - 1 {
            return cost;
        }
        if cost > dist[node][used_switch as usize] {
            continue;
        }

        // Normal edges
        for &(v, w) in &adj[node] {
            let next_cost = cost + w;
            if next_cost < dist[v][used_switch as usize] {
                dist[v][used_switch as usize] = next_cost;
                heap.push(State { cost: next_cost, node: v, used_switch });
            }
        }

        // Try flipping an incoming edge if not used switch yet
        if !used_switch {
            for &(u, w) in &rev_adj[node] {
                let next_cost = cost + 2 * w;
                if next_cost < dist[u][1] {
                    dist[u][1] = next_cost;
                    heap.push(State { cost: next_cost, node: u, used_switch: true });
                }
            }
        }
    }

    let res = std::cmp::min(dist[n-1][0], dist[n-1][1]);
    if res == i64::MAX { -1 } else { res }
}
